function getWxworkCode() {
  return new Promise((resolve, reject) => {
    wx.qy.login({
      success(res) {
        if (res.code) {
          resolve(res.code)
        } else {
          // 标准化返回 err
          reject({ message: '获取微信 code 失败' })
        }
      },
      fail() {
        // 标准化返回 err
        reject({ message: '获取微信 code 失败' })
      }
    })
  })
}
