function login(code) {
  return rest.auth.loginWithWxwork(code).then((res) => {
    const { code, data } = res
    // success：缓存 token，返回⻔店 id
    if ([0, 101].includes(code)) {
      commit('UPDATE_ACCESS_TOKEN', data['access-token'])
