4. 对外授权接⼝（企业微信）
/**
 * 登录授权
 * /
export function auth() {
  wx.showLoading({
    title: '加载中',
    mask: true
  })
  return getWxworkCode()
    .then((code) => login(code))
    .then((storeId) => selectStore(storeId))
    .catch((err) => {
      /**
      * err 标准化
      * { message: '' }
      */
      wx.showModal({
        title: '登录失败',
        confirmColor: '#1890FF',
        content: `${err.message || '⽹络异常'}，您可点击确定重新登录`,
        mask: true,
        showCancel: false,
        success: (res) => {
          if (res.confirm) {
            resolve(auth())
          }
        }
      })
    })
    .finally(wx.hideLoading)
  })
}
5. 对外授权接口（async await）
/**
 * 登录授权
 */
export async function auth() {
  try {
    wx.showLoading({
      title: '加载中',
      mask: true
    })
    const code = await getWxworkCode()
    const storeId = await login(code)
    await selectStore(storeId)
    wx.hideLoading()
  } catch (e) {
    wx.hideLoading()
    return new Promise((resolve) => {
      wx.showModal({
        title: '登录失败',
        confirmColor: '#1890FF',
        content: `${err.message || '⽹络异常'}，您可点击确定重新登录`,
        mask: true,
        showCancel: false,
        success: (res) => {
          if (res.confirm) {
            resolve(auth())
          }
        }
      })
    })
  }
}
